class Solution:
    def sortString(self, s: str) -> str:
        result = []
        while s:
            for c in sorted(set(s)):
                result.append(c)
                s = s.replace(c, '', 1)
            for c in sorted(set(s), reverse=True):
                result.append(c)
                s = s.replace(c, '', 1)
        return ''.join(result)
```
